__kernel void srad_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global float* d_dN,
    __global float* d_dS,
    __global float* d_dW,
    __global float* d_dE,
    __global float* c,
    __global float* d_I,
    const float q0sqr)
{
    int k = get_global_id(0);
    if (k >= Ne) return;

    int i = k / Nc;
    int j = k % Nc;

    // Clamp indices to valid range to avoid out-of-bounds
    int iN_idx = iN[i];
    int iS_idx = iS[i];
    int jW_idx = jW[j];
    int jE_idx = jE[j];

    if (iN_idx < 0) iN_idx = 0;
    if (iN_idx >= Nr) iN_idx = Nr - 1;
    if (iS_idx < 0) iS_idx = 0;
    if (iS_idx >= Nr) iS_idx = Nr - 1;
    if (jW_idx < 0) jW_idx = 0;
    if (jW_idx >= Nc) jW_idx = Nc - 1;
    if (jE_idx < 0) jE_idx = 0;
    if (jE_idx >= Nc) jE_idx = Nc - 1;

    float Jc = d_I[k];

    float dN = d_I[iN_idx * Nc + j] - Jc;
    float dS = d_I[iS_idx * Nc + j] - Jc;
    float dW = d_I[i * Nc + jW_idx] - Jc;
    float dE = d_I[i * Nc + jE_idx] - Jc;

    d_dN[k] = dN;
    d_dS[k] = dS;
    d_dW[k] = dW;
    d_dE[k] = dE;

    float G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
    float L = (dN + dS + dW + dE) / Jc;

    float num = 0.5f * G2 - (1.0f / 16.0f) * (L * L);
    float den = 1.0f + 0.25f * L;
    float qsqr = num / (den * den);

    den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
    float c_val = 1.0f / (1.0f + den);

    if (c_val < 0.0f) c_val = 0.0f;
    else if (c_val > 1.0f) c_val = 1.0f;

    c[k] = c_val;
}

__kernel void srad2_kernel(
    const float lambda,
    const int Nr,
    const int Nc,
    const long Ne,
    __global const int* iN,
    __global const int* iS,
    __global const int* jE,
    __global const int* jW,
    __global const float* d_dN,
    __global const float* d_dS,
    __global const float* d_dW,
    __global const float* d_dE,
    __global const float* c,
    __global float* d_I)
{
    int k = get_global_id(0);
    if (k >= Ne) return;

    int i = k / Nc;
    int j = k % Nc;

    // Clamp indices to valid range to avoid out-of-bounds
    int iS_idx = iS[i];
    int jE_idx = jE[j];

    if (iS_idx < 0) iS_idx = 0;
    if (iS_idx >= Nr) iS_idx = Nr - 1;
    if (jE_idx < 0) jE_idx = 0;
    if (jE_idx >= Nc) jE_idx = Nc - 1;

    float cN = c[k];
    float cS = c[iS_idx * Nc + j];
    float cW = c[k];
    float cE = c[i * Nc + jE_idx];

    float D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

    d_I[k] = d_I[k] + 0.25f * lambda * D;
}

__kernel void prepare_kernel(
    const long d_Ne,
    __global const float* d_I,
    __global float* d_sums,
    __global float* d_sums2)
{
    int ei = get_global_id(0);
    if (ei >= d_Ne) return;

    d_sums[ei] = d_I[ei];
    d_sums2[ei] = d_I[ei] * d_I[ei];
}

__kernel void reduce_kernel(
    const long d_Ne,
    const int d_no,
    const int d_mul,
    __global float* d_sums,
    __global float* d_sums2)
{
    int ei = get_global_id(0);
    int tx = get_local_id(0);
    int bx = get_group_id(0);
    int local_size = get_local_size(0);

    __local float d_psum[256]; // Adjust size if needed
    __local float d_psum2[256];

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    } else {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int nf = local_size - (get_num_groups(0) * local_size - d_no);
    int df = 0;

    if (nf == local_size) {
        for (int i = 2; i <= local_size; i <<= 1) {
            if (((tx + 1) % i) == 0) {
                d_psum[tx] += d_psum[tx - i / 2];
                d_psum2[tx] += d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }
        if (tx == local_size - 1) {
            d_sums[bx * d_mul * local_size] = d_psum[tx];
            d_sums2[bx * d_mul * local_size] = d_psum2[tx];
        }
    } else {
        if (bx != get_num_groups(0) - 1) {
            for (int i = 2; i <= local_size; i <<= 1) {
                if (((tx + 1) % i) == 0) {
                    d_psum[tx] += d_psum[tx - i / 2];
                    d_psum2[tx] += d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }
            if (tx == local_size - 1) {
                d_sums[bx * d_mul * local_size] = d_psum[tx];
                d_sums2[bx * d_mul * local_size] = d_psum2[tx];
            }
        } else {
            for (int i = 2; i <= local_size; i <<= 1) {
                if (nf >= i) df = i;
            }
            for (int i = 2; i <= df; i <<= 1) {
                if (((tx + 1) % i) == 0 && tx < df) {
                    d_psum[tx] += d_psum[tx - i / 2];
                    d_psum2[tx] += d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }
            if (tx == df - 1) {
                for (int i = (bx * local_size) + df; i < (bx * local_size) + nf; i++) {
                    d_psum[tx] += d_sums[i];
                    d_psum2[tx] += d_sums2[i];
                }
                d_sums[bx * d_mul * local_size] = d_psum[tx];
                d_sums2[bx * d_mul * local_size] = d_psum2[tx];
            }
        }
    }
}

__kernel void extract_kernel(
    const long d_Ne,
    __global float* d_I)
{
    int ei = get_global_id(0);
    if (ei >= d_Ne) return;

    d_I[ei] = exp(d_I[ei]);
}

__kernel void compress_kernel(
    const long d_Ne,
    __global float* d_I)
{
    int ei = get_global_id(0);
    if (ei >= d_Ne) return;

    d_I[ei] = log(d_I[ei]) * 255.0f;
}
